/**
 * ОПИСАНИЕ УЗЛА: "Сборка Контекста V.2.0"
 * 
 * ЧТО ДЕЛАЕТ:
 * 1. Собирает данные из источников: Очередь, Настройки, Промпты, Офферы, Опубликованное, Установка ID таблицы.
 * 2. Очищает их от технического мусора n8n.
 * 3. Создает единый объект "контекст", который прокидывается через всю систему.
 */

// 1) ИЗВЛЕКАЕМ ДАННЫЕ ИЗ ВСЕХ ВХОДЯЩИХ ВЕТОК
const задача = $('Чтение новой темы из очереди').first().json;

// ВАЖНО: .all() вернет массив items; .first().json — один item
const настройки_сырые = $('НАСТРОЙКИ').all();
const промпты_сырые = $('ПРОМПТЫ').all();
const офферы_сырые = $('ОФФЕРЫ').all();
const опубликовано_сырые = $('ОПУБЛИКОВАНО').all();

// Новый источник: Установка ID таблицы (Set node)
const установка_таблицы = (() => {
  try {
    // Если узел подключён и есть item — забираем json
    return $('Установка ID таблицы').item?.json ?? {};
  } catch (e) {
    // Если узла нет в графе/имя не совпало — не ломаем сборку
    return {};
  }
})();

// 2) ОБРАБОТКА НАСТРОЕК (Словарь Ключ-Значение)
const настройки = {};
настройки_сырые.forEach(item => {
  const строка = item.json;
  if (строка['Ключ']) {
    настройки[строка['Ключ']] = строка['Значение'];
  }
});

// 3) ОБРАБОТКА ПРОМПТОВ (Словарь по именам агентов)
const промпты = {};
промпты_сырые.forEach(item => {
  const строка = item.json;
  if (строка['Имя агента']) {
    промпты[строка['Имя агента']] = строка['Системный промпт'];
  }
});

// 4) ОБРАБОТКА ОФФЕРОВ (Только активные)
const база_офферов = офферы_сырые
  .filter(item => item.json['Статус'] === 'Active')
  .map(item => {
    const строка = item.json;
    return {
      id: строка['ID Оффера'],
      название: строка['Название'],
      контекст_ии: строка['Контекст ИИ'],
      ссылка: строка['Ссылка'],
      тип: строка['Тип'] // Soft или Hard
    };
  });

// 5) ОБРАБОТКА ОПУБЛИКОВАННЫХ СТАТЕЙ (База для перелинковки)
const база_ссылок = опубликовано_сырые.map(item => {
  const строка = item.json;
  return {
    ключ: строка['Ключ'],
    заголовок: строка['Заголовок'],
    ссылка: строка['Ссылка'],
    анкоры: строка['Анкоры для ссылок']
  };
});

// 6) НОРМАЛИЗУЕМ ДАННЫЕ ИЗ "Установка ID таблицы"
const инфраструктура = {
  table: установка_таблицы.table ?? null,
  domen: установка_таблицы.domen ?? null,
  wp_url: установка_таблицы.wp_url ?? установка_таблицы.domen ?? null
};

// 7) ФОРМИРУЕМ ФИНАЛЬНЫЙ КОНТЕКСТ
return {
  json: {
    контекст: {
      задача,
      настройки,
      промпты,
      база_офферов,
      база_опубликовано: база_ссылок,
      инфраструктура, // <-- добавили сюда
      мета: {
        дата_запуска: new Date().toLocaleString('ru-RU'),
        идентификатор_сессии: Math.random().toString(36).substring(7)
      }
    }
  }
};

