/**
 * ОПИСАНИЕ УЗЛА: "Генератор FAQ и Якорей V.3.0"
 */

const rawOutput = $input.item.json.output.replace(/```json\n?|```/g, "").trim();
const data = JSON.parse(rawOutput);

const faqArray = data.faq;
const anchors = data.link_anchors;

// 1. Создаем HTML версию (видимую)
let htmlView = `<div class="faq-section" style="max-width: 800px; margin: 30px auto;"><h2>Часто задаваемые вопросы</h2>`;
faqArray.forEach(item => {
    htmlView += `
    <details class="faq-item" style="margin-bottom: 15px; padding: 10px; border: 1px solid #eee; border-radius: 8px;">
        <summary style="font-weight: bold; cursor: pointer;">${item.q}</summary>
        <p style="margin-top: 10px;">${item.a}</p>
    </details>`;
});
htmlView += `</div>`;

// 2. Создаем версию для Google (JSON-LD)
const schemaData = {
    "@context": "https://schema.org",
    "@type": "FAQPage",
    "mainEntity": faqArray.map(item => ({
        "@type": "Question",
        "name": item.q,
        "acceptedAnswer": {
            "@type": "Answer",
            "text": item.a
        }
    }))
};

const jsonLdCode = `<script type="application/ld+json">${JSON.stringify(schemaData)}</script>`;

// 3. Возвращаем всё, включая анкоры для GSheets
return {
    json: {
        faq_html: htmlView,
        faq_schema: jsonLdCode,
        link_anchors: anchors // Это поле пойдет в GSheets
    }
};

/**
 * УЗЕЛ: Финальный сборщик V.7.5 (ANTI-NULL & STABLE)
 * 
 * ЧТО ИСПРАВЛЕНО:
 * 1. Запрещен вывод слова "null" в заголовках и тексте.
 * 2. Если h2_title пустой, тег <h2> не создается.
 * 3. Если контент блока пуст, блок полностью игнорируется.
 * 4. Если у изображения есть alt, figcaption синхронизируется с alt.
 */

const DESKTOP_MAX_WIDTH = '760px';   
const TEXT_COLOR        = '#222222'; 
const LINK_COLOR        = '#0056b3'; 

// 1. ЗАГРУЗКА ДАННЫХ
const hook = $(['ВФ 2']).first().json; 
const bodyBlocks = $(['ВФ 3']).first().json.blocks; 
const faq = $(['Генератор FAQ-разметки']).first().json;
const author = $(['Обо мне']).first().json;
const contextNode = $(['Сборка Контекста']).first().json.контекст;
const rawDomen = $('Установка ID таблицы').first().json.domen;
const myDomain = rawDomen.replace(/^https?:\/\//, '').split('/')[0].replace('next.', '');

// 2. ФУНКЦИЯ ОЧИСТКИ (Защита от null + синхронизация alt/figcaption)
function sanitizeContent(html, linkData = null) {
    if (!html || html === "null" || html === null) return "";

    let cleanHtml = html;

    // Внешние ссылки с Title
    const linkRegex = /<a\s+[^>]*?href=(["'])(.*?)\1[^>]*?>/gi;
    cleanHtml = cleanHtml.replace(linkRegex, (fullTag, quote, url) => {
        const isExternal = url.startsWith('http') && !url.includes(myDomain);
        if (isExternal) {
            let titleAttr = "";
            if (linkData && linkData.portal) {
                const desc = linkData.description ? linkData.description.substring(0, 60).replace(/"/g, "'") : "";
                titleAttr = `title="Источник: ${linkData.portal} — ${desc}"`;
            }
            return `<a href="${url}" ${titleAttr} target="_blank" rel="nofollow noopener">`;
        }
        return fullTag;
    });

    // Синхронизация figcaption с alt у img внутри figure
    cleanHtml = cleanHtml.replace(/<figure\b[^>]*>[\s\S]*?<\/figure>/gi, (figureHtml) => {
        const imgAltMatch = figureHtml.match(/<img\b[^>]*\balt=(["'])(.*?)\1[^>]*>/i);
        if (!imgAltMatch) return figureHtml;

        const altText = imgAltMatch[2] ? imgAltMatch[2].trim() : "";
        if (!altText || altText.toLowerCase() === "null") return figureHtml;

        if (/<figcaption\b[^>]*>[\s\S]*?<\/figcaption>/i.test(figureHtml)) {
            return figureHtml.replace(
                /<figcaption\b([^>]*)>[\s\S]*?<\/figcaption>/i,
                `<figcaption$1>${altText}</figcaption>`
            );
        }

        return figureHtml.replace(/<\/figure>/i, `<figcaption>${altText}</figcaption></figure>`);
    });

    // Таблицы, гигиена
    cleanHtml = cleanHtml.replace(/<table/gi, '<div class="table-container" style="overflow-x:auto;-webkit-overflow-scrolling:touch;margin:20px 0;border-radius:8px;border:1px solid #eee;width:100%"><table');
    cleanHtml = cleanHtml.replace(/<\/table>/gi, '</table></div>');
    cleanHtml = cleanHtml.replace(/<\/p>\s*<\/p>/gi, '</p>'); 
    cleanHtml = cleanHtml.replace(/<p><\/p>/gi, ''); 

    // Финальный фильтр: если ИИ всё же вставил текстовое "null"
    return cleanHtml.replace(/>\s*null\s*</gi, '><');
}

// 3. ГЕНЕРАЦИЯ СОДЕРЖАНИЯ (TOC) - Только если есть заголовки
let tocHtml = "";
const validH2Blocks = bodyBlocks.filter(b => b.header_tag === 'h2' && b.title && b.title !== "null");

if (validH2Blocks.length > 0) {
    tocHtml = `<div class="toc-box" style="background:#f8f9fa; padding:20px 15px; border-radius:12px; margin:30px auto; max-width:${DESKTOP_MAX_WIDTH}; box-sizing:border-box; border:1px solid #eee;"><strong style="font-size:20px; display:block; margin-bottom:10px;">Содержание:</strong><ul style="margin:0; padding:0 0 0 20px; line-height:1.6; font-size:17px;">`;
    validH2Blocks.forEach(block => {
        tocHtml += `<li style="margin-bottom:8px;"><a href="#section-${block.id}" style="color:${LINK_COLOR}; text-decoration:underline;">${block.title}</a></li>`;
    });
    tocHtml += `</ul></div>`;
}

// 4. СБОРКА ТЕЛА
let bodyHtml = "";
bodyBlocks.forEach(block => {
    let content = sanitizeContent(block.content, block.external_linking);
    if (!content || content.trim() === "") return; // Пропускаем пустые блоки

    if (block.type === 'IMG' || block.type === 'VIDEO' || block.type === 'HARD_OFFER') {
        // Блоки с собственной версткой заголовков (или без них)
        bodyHtml += `<div class="article-special-block" style="width:100%; margin:40px 0;">${content}</div>`;
    } else {
        // Текстовые блоки
        const tag = block.header_tag || 'h2';
        const title = (block.title && block.title !== "null") ? block.title : "";
        const headerHtml = title ? `<${tag} id="section-${block.id}" style="margin-top:45px; margin-bottom:20px; font-size:clamp(24px, 6vw, 34px); line-height:1.2; font-weight:800; hyphens:auto; word-wrap:break-word;">${title}</${tag}>` : "";

        bodyHtml += `
        <div class="article-text-block" style="max-width:${DESKTOP_MAX_WIDTH}; margin:0 auto; padding:0 10px; box-sizing:border-box;">
            ${headerHtml}
            <div style="font-size:19px; line-height:1.75; hyphens:auto; color:#333;">
                ${content}
            </div>
        </div>\n\n`;
    }
});

// 5. СКЛЕЙКА ФИНАЛЬНОГО ПОЛОТНА
let fullHtml = `
<div class="cyberseo-article-root" style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Helvetica,Arial,sans-serif; color:${TEXT_COLOR}; background:transparent; width:100%; overflow-x:hidden;">
    <div class="article-intro" style="max-width:${DESKTOP_MAX_WIDTH}; margin:0 auto 30px auto; padding:0 10px; font-size:20px; line-height:1.7; box-sizing:border-box;">
        ${sanitizeContent(hook.result)}
    </div>
    ${tocHtml ? `<div style="padding:0 5px;">${tocHtml}</div>` : ""}
    <div class="article-content-flow">${bodyHtml}</div>
    <div class="article-faq" style="max-width:${DESKTOP_MAX_WIDTH}; margin:50px auto; padding:0 10px; box-sizing:border-box;">${faq.faq_html}</div>

    <div class="author-card" style="max-width:${DESKTOP_MAX_WIDTH}; margin:60px auto 0 auto; padding:20px; background:#fafafa; border:1px solid #eee; border-radius:16px; box-sizing:border-box;">
        <div style="display:flex; flex-wrap:wrap; align-items:center; gap:20px;">
            <img src="${(author.avatar_urls && (author.avatar_urls['96'] || author.avatar_urls['48'] || Object.values(author.avatar_urls)[0])) || ''}" alt="Автор: ${author.name || 'Автор'}" style="width:65px; height:65px; border-radius:50%; border:2px solid #7a00ff; object-fit:cover;">
            <div style="flex:1; min-width:200px;">
                <h4 style="margin:0 0 5px 0; font-size:19px; font-weight:700;">Автор: ${author.name}</h4>
                <p style="margin:0; font-size:15px; color:#555; line-height:1.5;">${author.description}</p>
                <a href="${author.link}" style="display:inline-block; margin-top:8px; color:${LINK_COLOR}; text-decoration:none; font-weight:bold; font-size:15px;">Все статьи автора →</a>
            </div>
        </div>
    </div>
</div>
${faq.faq_schema}`;

// 6. ВЫХОД
const plainText = fullHtml.replace(/<[^>]*>/g, ' ');
const wordCount = plainText.trim().split(/\s+/).length;
const readingTime = Math.ceil(wordCount / 200);

const __metaD = (() => { let m=(hook.meta_description||'').trim(); if(m.length<=155) return m; let c=m.slice(0,155); const __e=Math.max(c.lastIndexOf('.'),c.lastIndexOf('!'),c.lastIndexOf('?')); if(__e>=60){ return c.slice(0,__e+1).trim(); } const s=c.lastIndexOf(' '); return (s>100?c.slice(0,s):c).trim(); })();

return [{
    json: {
        title: hook.h1,
        content: fullHtml,
        slug: hook.slug,
        excerpt: __metaD,
        featured_media: hook.featured_image.mediaId,
        status: "publish",
        meta: {
            "_yoast_wpseo_metadesc": __metaD,
            "_yoast_wpseo_focuskw": contextNode.задача['Главный ключ'],
            "reading_time": readingTime.toString()
        }
    }
}];

/**
 * УЗЕЛ: SEO Sanitizer & HTML Cleaner V.3.0 (GOLD)
 * ЧТО ДЕЛАЕТ: 
 * 1. Берет домен из ноды "Установка ID таблицы".
 * 2. Для ВНЕШНИХ ссылок: Сносит все атрибуты и ставит эталонные (nofollow, noopener, _blank).
 * 3. Для ВНУТРЕННИХ ссылок: Оставляет как есть (поддерживает относительные и абсолютные).
 * 4. Очищает HTML от двойных закрывающих тегов и пустых абзацев.
 */

// 1. ПОДГОТОВКА ДАННЫХ
const article = $input.item.json; 
let html = article.content || "";

// Берем домен из глобальных настроек (Set нода)
const rawDomen = $('Установка ID таблицы').first().json.domen;

// Очищаем домен для сравнения: "https://next.autopipe.space/" -> "autopipe.space"
const myDomain = rawDomen.replace(/^https?:\/\//, '').split('/')[0].replace('next.', '');

// 2. ЛОГИКА ОБРАБОТКИ ССЫЛОК
// Регулярка находит весь тег <a> и отдельно URL в href
const linkRegex = /<a\s+[^>]*?href=(["'])(.*?)\1[^>]*?>/gi;

html = html.replace(linkRegex, (fullTag, quote, url) => {
    // Ссылка внешняя, если начинается с http и не содержит наш домен
    const isExternal = url.startsWith('http') && !url.includes(myDomain);

    if (isExternal) {
        // ПЕРЕСБОРКА ТЕГА С НУЛЯ (Гарантия отсутствия дублей атрибутов)
        return `<a href="${url}" target="_blank" rel="nofollow noopener">`;
    }

    // Если ссылка внутренняя — возвращаем оригинал без изменений
    return fullTag;
});

// 3. ГИГИЕНА HTML (Чистка артефактов ИИ)
html = html.replace(/<\/p>\s*<\/p>/gi, '</p>');      // Удаление двойных закрывающих </p>
html = html.replace(/<p><\/p>/gi, '');              // Удаление пустых абзацев
html = html.replace(/<p>&nbsp;<\/p>/gi, '');         // Удаление абзацев с неразрывным пробелом
html = html.replace(/\n\s*\n/g, '\n');              // Схлопывание лишних пустых строк

// 3.5 САНИТАЙЗЕР ССЫЛОК: убираем гиперссылки с не-ASCII/пробелами в URL (битые адреса от модели → оставляем только текст)
html = html.replace(/<a\b[^>]*\bhref="([^"]*)"[^>]*>([\s\S]*?)<\/a>/gi, (m, href, text) => (/[^\x21-\x7E]/.test(href) ? text : m));

// 4. ВОЗВРАТ ОБЪЕКТА
return {
    json: {
        ...article,        // Пробрасываем все поля (title, slug, excerpt, mediaId)
        content: html,     // Заменяем контент на очищенный
        sanitized: true,   // Флаг успешной проверки
        detected_root_domain: myDomain
    }
};

const user = $json;
return [{
  json: {
    name: user.name || '',
    avatar_url: user.avatar_urls?.['96'] || user.avatar_urls?.['48'] || '',
    description: user.description || '',
    link: user.link || user.url || ''
  }
}];

const tagsRaw = $('ВФ 1').first().json.tags || '';
let tagNames = Array.isArray(tagsRaw)
  ? tagsRaw.map(t => String(t).trim()).filter(Boolean)
  : String(tagsRaw).split(',').map(t => t.trim()).filter(Boolean);
if (tagNames.length === 0) {
  // фолбэк: досье не дало тегов — не блокируем публикацию, берём главный ключ
  let key = '';
  try { key = ($('Чтение новой темы из очереди').first().json['Главный ключ'] || '').toString().trim(); } catch(e){}
  tagNames = key ? [key] : ['Маркетинг'];
}
return tagNames.map(name => ({ json: { name } }));

// Накопление tag ID на каждой итерации цикла
const staticData = $getWorkflowStaticData('global');
if (!staticData.collectedTagIds) {
  staticData.collectedTagIds = [];
}

const item = $input.first();
const directId = item.json.id || (item.json.body && item.json.body.id);
if (directId) {
  staticData.collectedTagIds.push(directId);
} else if (item.json.error) {
  const msg = String(item.json.error.message || JSON.stringify(item.json.error));
  const match = msg.match(/term_id["\\\s]*:\s*(\d+)/);
  if (match) {
    staticData.collectedTagIds.push(parseInt(match[1]));
  } else {
    const match2 = msg.match(/additional_data["\\\s]*:\s*\[(\d+)/);
    if (match2) {
      staticData.collectedTagIds.push(parseInt(match2[1]));
    }
  }
}

return $input.all();

// Читаем накопленные tag IDs из staticData
const staticData = $getWorkflowStaticData('global');
const tagIds = staticData.collectedTagIds || [];

// Очищаем после чтения
staticData.collectedTagIds = [];

return [{ json: { tag_ids: tagIds } }];

return [{ json: { 
  postId: $json.id, 
  url: $json.link, 
  title: $json.title?.rendered || '' 
} }];

/**
 * УЗЕЛ: Очистка досье V.11.0
 *
 * ЛОГИКА:
 * - если агент вернул пустой / невалидный ответ, увеличиваем счетчик в static data
 * - если попыток >= 3 -> throw Error
 * - если ответ валидный -> счетчик сбрасываем в 0
 * - все входные данные и контекст протаскиваем дальше
 */

const MAX_ATTEMPTS = 3;
const state = $getWorkflowStaticData('node');

if (typeof state.failCount !== 'number') {
	state.failCount = 0;
}

const item = $input.first()?.json || {};
const rawOutput = typeof item.output === 'string' ? item.output : '';

const sourceContext =
	item.контекст ||
	item.source_context ||
	item.source_payload?.контекст ||
	$('When Executed by Another Workflow').first()?.json?.контекст ||
	null;

const sourcePayload =
	item.source_payload ||
	$('When Executed by Another Workflow').first()?.json ||
	item;

const CONFIG = {
	keys: {
		text: 'dossier_text',
		sources: 'external_sources',
		tags: 'tags'
	},
	defaults: {
		dossier_content: 'Текст не найден',
		external_sources: [],
		tags: []
	}
};

function extractJson(str) {
	if (!str || typeof str !== 'string') return null;

	let cleaned = str.trim();

	// Убираем markdown code fences
	cleaned = cleaned
		.replace(/^```json\s*/i, '')
		.replace(/^```\s*/i, '')
		.replace(/\s*```$/i, '')
		.trim();

	// 1. Пробуем распарсить строку как есть
	try {
		return JSON.parse(cleaned);
	} catch (_) {}

	// 2. Если вокруг есть мусор, вырезаем объект от первой { до последней }
	try {
		const firstBrace = cleaned.indexOf('{');
		const lastBrace = cleaned.lastIndexOf('}');

		if (firstBrace === -1 || lastBrace === -1 || lastBrace <= firstBrace) {
			return null;
		}

		const jsonCandidate = cleaned.slice(firstBrace, lastBrace + 1);
		return JSON.parse(jsonCandidate);
	} catch (_) {
		return null;
	}
}

function normalizeData(data, raw) {
	if (!data || typeof data !== 'object' || Array.isArray(data)) {
		return {
			...CONFIG.defaults,
			dossier_content: raw.trim() || CONFIG.defaults.dossier_content,
			parsing_error: 'JSON not found, raw text preserved'
		};
	}

	const dossier_content =
		typeof data[CONFIG.keys.text] === 'string' && data[CONFIG.keys.text].trim()
			? data[CONFIG.keys.text].trim()
			: raw.trim() || CONFIG.defaults.dossier_content;

	const external_sources = Array.isArray(data[CONFIG.keys.sources])
		? data[CONFIG.keys.sources]
		: [];

	const tags = Array.isArray(data[CONFIG.keys.tags])
		? data[CONFIG.keys.tags]
		: [];

	return {
		dossier_content,
		external_sources,
		tags,
		has_sources: external_sources.length > 0,
		has_tags: tags.length > 0
	};
}

function isFailure(result, raw) {
	const safeRaw = typeof raw === 'string' ? raw.trim() : '';
	const rawIsEmpty = safeRaw === '';

	const noUsefulText =
		!result?.dossier_content ||
		result.dossier_content.trim() === '' ||
		result.dossier_content.trim() === CONFIG.defaults.dossier_content;

	const noSources =
		!Array.isArray(result?.external_sources) ||
		result.external_sources.length === 0;

	return rawIsEmpty || (noUsefulText && noSources);
}

const parsedData = extractJson(rawOutput);
const normalized = normalizeData(parsedData, rawOutput);
const failed = isFailure(normalized, rawOutput);

if (failed) {
	state.failCount += 1;

	if (state.failCount >= MAX_ATTEMPTS) {
		state.failCount = 0;
		throw new Error(
			`Следователь темы не смог вернуть валидное досье после ${MAX_ATTEMPTS} попыток`
		);
	}

	return {
		json: {
			...normalized,
			needs_retry: true,
			agent_status: 'retry',
			retry_reason: 'empty_or_invalid_agent_response',

			retry_count: state.failCount,
			retries_left: MAX_ATTEMPTS - state.failCount,

			контекст: sourceContext,
			source_context: sourceContext,
			source_payload: sourcePayload,

			raw_output: rawOutput,
			is_empty_output: rawOutput.trim() === '',
			is_json_parsed: !!parsedData
		}
	};
}

// Если все ок — сбрасываем счетчик
state.failCount = 0;

return {
	json: {
		...normalized,
		needs_retry: false,
		agent_status: 'success',
		retry_reason: null,

		retry_count: 0,
		retries_left: MAX_ATTEMPTS,

		контекст: sourceContext,
		source_context: sourceContext,
		source_payload: sourcePayload,

		raw_output: rawOutput,
		is_empty_output: rawOutput.trim() === '',
		is_json_parsed: !!parsedData
	}
};

/**
 * УЗЕЛ: Валидатор Плана V2
 *
 * Что делает:
 * - парсит output от АРХИТЕКТОР
 * - валидирует структуру плана
 * - валидирует офферы, offer_url и типы
 * - валидирует external/internal ссылки
 * - проверяет пустой план
 * - нормализует offer_url / external portal по канону
 *
 * Ожидает на входе:
 * - $input.item.json.output -> JSON-массив плана или объект { blocks: [...] }
 * - $('Парсинг LSI').first().json
 * - $('Очистка досье').first().json
 * - $('Соединение данных').first().json
 */

const inputItem = $input.first()?.json || {};
const _retryState = $getWorkflowStaticData('node');
if (typeof _retryState.archRetryCount !== 'number') _retryState.archRetryCount = 0;
const rawOutput = typeof inputItem.output === 'string' ? inputItem.output : '';

const errors = [];

// -----------------------------------------------------------------------------
// HELPERS
// -----------------------------------------------------------------------------

function stripMarkdownFences(str) {
	if (!str || typeof str !== 'string') return '';
	return str.replace(/```json\s*|```/gi, '').trim();
}

function safeJsonParse(str) {
	try {
		return JSON.parse(str);
	} catch {
		return null;
	}
}

function isNonEmptyObject(value) {
	return !!value && typeof value === 'object' && !Array.isArray(value) && Object.keys(value).length > 0;
}

function normalizePlan(raw) {
	const cleaned = stripMarkdownFences(raw);

	if (!cleaned) {
		errors.push('Пустой ответ от Архитектора.');
		return { blocks: [] };
	}

	const parsed = safeJsonParse(cleaned);

	if (!parsed) {
		errors.push('JSON Syntax Error: не удалось распарсить output Архитектора.');
		return { blocks: [] };
	}

	if (Array.isArray(parsed)) {
		return { blocks: parsed };
	}

	if (parsed && Array.isArray(parsed.blocks)) {
		return { blocks: parsed.blocks };
	}

	errors.push('Структура плана некорректна: ожидается JSON-массив или объект с полем blocks.');
	return { blocks: [] };
}

function parseInternalLinks(rawInternal) {
	if (!rawInternal || typeof rawInternal !== 'string') return [];
	const trimmed = rawInternal.trim();

	if (!trimmed || trimmed === 'Внутренних ссылок пока нет') return [];

	const cleaned = stripMarkdownFences(trimmed);
	const parsed = safeJsonParse(cleaned);

	return Array.isArray(parsed) ? parsed.filter(isNonEmptyObject) : [];
}

function collectOffers(context) {
	const offers = Array.isArray(context?.база_офферов) ? context.база_офферов : [];
	const map = new Map();

	for (const offer of offers) {
		if (offer && offer.id !== undefined && offer.id !== null) {
			map.set(String(offer.id), offer);
		}
	}

	return {
		all: offers,
		map,
		soft: offers.filter(o => String(o?.тип || '').toLowerCase() === 'soft'),
		hard: offers.filter(o => String(o?.тип || '').toLowerCase() === 'hard'),
	};
}

// -----------------------------------------------------------------------------
// SOURCE DATA
// -----------------------------------------------------------------------------

let geoData = {};
let dossierData = {};
let connectionData = {};

try {
	geoData = $('Парсинг LSI').first()?.json || {};
} catch (e) {
	geoData = {};
}

try {
	dossierData = $('Очистка досье').first()?.json || {};
} catch (e) {
	dossierData = {};
}

try {
	connectionData = $('Соединение данных').first()?.json || {};
} catch (e) {
	connectionData = {};
}

// Контекст: берём из Merge, fallback на Очистку досье, fallback на триггер
let context = connectionData?.контекст || dossierData?.контекст || {};
try {
	if (!context || Object.keys(context).length === 0) {
		context = $('When Executed by Another Workflow').first()?.json?.контекст || {};
	}
} catch (e) {
	// keep whatever we have
}
const externalSources = Array.isArray(dossierData?.external_sources) ? dossierData.external_sources : [];
const internalLinks = parseInternalLinks(connectionData?.output);

const offerData = collectOffers(context);

const externalMap = new Map();
for (const src of externalSources) {
	if (src?.url) externalMap.set(String(src.url), src);
}

const internalMap = new Map();
for (const link of internalLinks) {
	if (link?.url) internalMap.set(String(link.url), link);
}

// -----------------------------------------------------------------------------
// PARSE PLAN
// -----------------------------------------------------------------------------

const plan = normalizePlan(rawOutput);
const blocks = Array.isArray(plan.blocks) ? plan.blocks : [];

if (blocks.length === 0) {
	errors.push('Пустой план: Архитектор не вернул ни одного блока.');
}

// -----------------------------------------------------------------------------
// BASIC STRUCTURE CHECKS
// -----------------------------------------------------------------------------

if (blocks.length > 0) {
	if (blocks.length < 13 || blocks.length > 16) {
		errors.push(`Неверное количество блоков: ${blocks.length}. Нужно от 13 до 16.`);
	}

	for (let i = 0; i < blocks.length; i++) {
		const expectedId = i + 1;
		if (blocks[i]?.id !== expectedId) {
			errors.push(`Нарушена последовательность id: ожидался id=${expectedId}, получен id=${blocks[i]?.id ?? 'null'}.`);
		}
	}

	const lastBlock = blocks[blocks.length - 1];
	if (lastBlock?.type !== 'HARD_OFFER') {
		errors.push('Последний блок должен быть HARD_OFFER.');
	}

	const imgAfter12 = blocks.findIndex((block, index) => block?.type === 'IMG' && index >= 12);
	if (imgAfter12 !== -1) {
		errors.push(`IMG нельзя размещать после 12 блока. Нарушение в блоке id=${blocks[imgAfter12]?.id}.`);
	}

	const tableCount = blocks.filter(block => block?.type === 'TABLE').length;
	if (tableCount !== 2) {
		errors.push(`Неверное количество TABLE-блоков: ${tableCount}. Нужно ровно 2.`);
	}

	const verdictIndex = blocks.findIndex(
		block =>
			block?.type === 'TEXT' &&
			(typeof block?.h2_title === 'string') &&
			['Заключение', 'Итоги'].includes(block.h2_title.trim())
	);

	if (verdictIndex === -1) {
		errors.push('Не найден блок TEXT с заголовком "Заключение" или "Итоги".');
	} else if (verdictIndex !== blocks.length - 2) {
		errors.push('Блок "Заключение" / "Итоги" должен быть предпоследним.');
	}
}

// -----------------------------------------------------------------------------
// TOPIC ANTI-HALLUCINATION CHECK
// -----------------------------------------------------------------------------

const forbiddenMetaWords = [
	'json-план',
	'json план',
	'json',
	'workflow',
	'контент-план',
	'seo-план',
	'валидац',
	'автоматизац',
];

for (const block of blocks) {
	const haystack = `${block?.h2_title || ''} ${block?.context || ''}`.toLowerCase();
	if (forbiddenMetaWords.some(word => haystack.includes(word))) {
		errors.push(`Блок id=${block?.id} ушел в мета-тему вместо темы статьи.`);
		break;
	}
}

// -----------------------------------------------------------------------------
// OFFER CHECKS + NORMALIZATION
// -----------------------------------------------------------------------------

const offerBlocks = blocks.filter(block => block?.type === 'SOFT_OFFER' || block?.type === 'HARD_OFFER');

if (offerData.all.length === 1) {
	if (offerBlocks.length !== 1) {
		errors.push(`При одном реальном оффере должен быть ровно один офферный блок. Сейчас: ${offerBlocks.length}.`);
	}
}

if (offerData.all.length > 1 && offerData.soft.length > 0 && offerData.hard.length > 0) {
	const softCount = offerBlocks.filter(block => block?.type === 'SOFT_OFFER').length;
	const hardCount = offerBlocks.filter(block => block?.type === 'HARD_OFFER').length;

	if (softCount !== 1) {
		errors.push(`Если доступны Soft и Hard, должен быть ровно один SOFT_OFFER. Сейчас: ${softCount}.`);
	}
	if (hardCount !== 1) {
		errors.push(`Если доступны Soft и Hard, должен быть ровно один HARD_OFFER. Сейчас: ${hardCount}.`);
	}
}

for (const block of offerBlocks) {
	const offerId = block?.offer_id;

	if (offerId === null || offerId === undefined || offerId === '') {
		errors.push(`В офферном блоке id=${block?.id} отсутствует offer_id.`);
		continue;
	}

	const canonicalOffer = offerData.map.get(String(offerId));

	if (!canonicalOffer) {
		errors.push(`В блоке id=${block?.id} указан несуществующий offer_id=${offerId}.`);
		continue;
	}

	// Особое правило:
	// - финальный блок всегда HARD_OFFER
	// - если оффер один и он Soft, это допустимо только для финального HARD_OFFER
	if (String(canonicalOffer?.тип || '').toLowerCase() === 'soft' && block.type === 'HARD_OFFER') {
		const isSingleOfferSoftFallback =
			offerData.all.length === 1 &&
			offerBlocks.length === 1 &&
			block.id === blocks[blocks.length - 1]?.id;

		if (!isSingleOfferSoftFallback) {
			errors.push(`Блок id=${block?.id}: Soft-оффер можно использовать как HARD_OFFER только как единственный финальный оффер.`);
		}
	}

	if (String(canonicalOffer?.тип || '').toLowerCase() === 'hard' && block.type === 'SOFT_OFFER') {
		errors.push(`Блок id=${block?.id}: Hard-оффер нельзя использовать как SOFT_OFFER.`);
	}

	// Нормализация offer_url
	const canonicalUrl = canonicalOffer?.ссылка || null;
	if (canonicalUrl) {
		block.offer_url = canonicalUrl;
	} else {
		block.offer_url = null;
	}
}

// -----------------------------------------------------------------------------
// EXTERNAL LINK CHECKS + NORMALIZATION
// -----------------------------------------------------------------------------

let usedExternalCount = 0;

for (const block of blocks) {
	const ext = block?.external_linking;

	if (!ext) continue;

	if (!isNonEmptyObject(ext)) {
		errors.push(`В блоке id=${block?.id} external_linking имеет некорректную структуру.`);
		continue;
	}

	const canonical = externalMap.get(String(ext.url || ''));

	if (!canonical) {
		errors.push(`В блоке id=${block?.id} используется внешний URL, которого нет в реестре: ${ext.url || 'null'}.`);
		continue;
	}

	usedExternalCount += 1;

	// Нормализуем portal
	block.external_linking = {
		url: canonical.url,
		portal: canonical.portal || ext.portal || null,
		description: ext.description || canonical.context || null,
	};
}

if (externalSources.length > 0 && usedExternalCount === 0) {
	errors.push('Во входных данных есть внешние источники, но ни один не распределен по блокам.');
}

// -----------------------------------------------------------------------------
// INTERNAL LINK CHECKS + NORMALIZATION
// -----------------------------------------------------------------------------

let usedInternalCount = 0;

for (const block of blocks) {
	const internal = block?.internal_linking;

	if (!internal) continue;

	if (!isNonEmptyObject(internal)) {
		errors.push(`В блоке id=${block?.id} internal_linking имеет некорректную структуру.`);
		continue;
	}

	const canonical = internalMap.get(String(internal.url || ''));

	if (!canonical) {
		errors.push(`В блоке id=${block?.id} используется внутренняя ссылка, которой нет во входных данных: ${internal.url || 'null'}.`);
		continue;
	}

	usedInternalCount += 1;

	block.internal_linking = {
		url: canonical.url,
		anchor: internal.anchor || canonical.anchor || null,
		topic: internal.topic || canonical.topic || null,
	};
}

if (internalLinks.length > 0 && usedInternalCount === 0) {
	errors.push('Во входных данных есть внутренние ссылки, но ни одна не распределена по блокам.');
}

// -----------------------------------------------------------------------------
// FINAL OUTPUT
// -----------------------------------------------------------------------------

// Update retry counter
if (errors.length === 0) {
	_retryState.archRetryCount = 0; // Success - reset
} else {
	_retryState.archRetryCount += 1; // Failure - increment
}

return {
	json: {
		isValid: errors.length === 0,
		error_report: errors.join(' | '),
		final_plan: { blocks },
		languageCode: geoData.languageCode || 'ru',
		lsi_keywords: geoData.lsi_keywords || '',
		dossier_content: dossierData.dossier_content || '',
		tags: dossierData.tags || [],
		контекст: context || {},
		retry_index: _retryState.archRetryCount,
		debug: {
			external_sources_count: externalSources.length,
			internal_links_count: internalLinks.length,
			offers_count: offerData.all.length,
			soft_offers_count: offerData.soft.length,
			hard_offers_count: offerData.hard.length,
			used_external_links: usedExternalCount,
			used_internal_links: usedInternalCount,
			offer_blocks_count: offerBlocks.length,
		},
	},
};

