/**
 * УЗЕЛ: Фильтр Офферов (ГЛАВНЫЙ + ПРОТИВОПОЛОЖНЫЕ)
 * Окружение: n8n Code node
 */

// 1. Извлечение данных с защитой от пустых значений
const context = $input.item.json["контекст"] || {};
const task = context["задача"] || {};
const allOffers = context["база_офферов"] || [];

// 2. Конфигурация ключей (кириллица)
const KEYS = {
    targetId: task["ID Оффера"],
    offerId: "id",
    offerType: "тип",
    types: {
        soft: "Soft",
        hard: "Hard"
    }
};

/**
 * Основная логика фильтрации
 */
function getFilteredOffers() {
    // Поиск основного оффера (приведение к строке для сравнения цифр и текста)
    const selectedOffer = allOffers.find(offer => 
        String(offer[KEYS.offerId]) === String(KEYS.targetId)
    );

    // Если главный оффер не найден, возвращаем базу как есть или пустую структуру
    if (!selectedOffer) {
        return {
            выбранный_оффер: null,
            доп_офферы: [],
            статус: "Ошибка: ID не найден"
        };
    }

    // Определяем тип-антагонист
    const mainType = selectedOffer[KEYS.offerType];
    const oppositeType = (mainType === KEYS.types.soft) ? KEYS.types.hard : KEYS.types.soft;

    // Собираем альтернативные офферы только противоположного типа
    const alternatives = allOffers.filter(offer => 
        offer[KEYS.offerType] === oppositeType
    );

    return {
        выбранный_оффер: selectedOffer,
        доп_офферы: alternatives,
        статус: "Успешно"
    };
}

// ВЫВОД
return {
    json: getFilteredOffers()
};

/**
 * УЗЕЛ: Финальный выход ВФ 1
 * Собирает данные из Валидатора и оригинального контекста
 * и возвращает полный объект для ВФ 2 и ВФ 3
 */

// Данные валидатора (план, dossier, tags и т.д.)
let validatorData = {};
try {
  validatorData = $('Валидатор Плана').first().json || {};
} catch(e) {
  validatorData = $input.item.json || {};
}

// Оригинальный контекст из триггера
let triggerData = {};
try {
  triggerData = $('When Executed by Another Workflow').first().json || {};
} catch(e) {}

// Собираем финальный объект
const output = {
  ...validatorData,
  // Гарантируем что контекст есть
  контекст: validatorData.контекст || triggerData.контекст || {},
  // Гарантируем languageCode
  languageCode: validatorData.languageCode || triggerData.languageCode || 'ru'
};

return { json: output };

