const response = $input.first()?.json || {};
const content = typeof response.output === 'string' ? response.output : response.text || '';

// Remove markdown fences if present
const cleaned = content.replace(/```json\\s*|```/gi, '').trim();

// Try to parse JSON
let lsiArray = [];
try {
    const parsed = JSON.parse(cleaned);
    lsiArray = Array.isArray(parsed) ? parsed : [];
} catch (e) {
    // If parsing fails, treat as empty
    lsiArray = [];
}

// Return in the same format the original node did
return {
    json: {
        lsi_keywords: lsiArray,
        languageCode: 'ru'
    }
};

/**
 * СБОРКА УНИФИЦИРОВАННОГО ХУКА (КИРПИЧ №1) — HTML ВЕРСИЯ
 */

// 1. ПОЛУЧАЕМ ДАННЫЕ
const journalistNode = $(['Агент Журналист']).first();
const rawJournalist = journalistNode.json.output;
const journalist = JSON.parse(rawJournalist.replace(/```json\n?|```/g, ""));
const imageGen = $(['Генерация изображения']).first().json;
const trigger = $(['When Executed by Another Workflow']).first().json;

// 2. СОБИРАЕМ СОДЕРЖИМОЕ (Сначала Саммари, потом Лид)
// Мы просто складываем две HTML-строки
const htmlContent = `${journalist.summary_html}\n\n${journalist.intro_html}`;

// 3. ФОРМИРУЕМ КИРПИЧ №1
return {
  json: {
    id: 1,                 // Порядковый номер для Мастера
    type: "HOOK",          // Тип блока
    h1: journalist.h1,     // Чистый заголовок для <h1>
    slug: journalist.slug,
    meta_description: journalist.meta_description,
    excerpt: journalist.meta_description,

    // Результат (Контент блока в чистом HTML)
    result: htmlContent, 

    // Медиа (Данные обложки для WordPress)
    featured_image: {
        url: imageGen.mediaUrl,
        alt: imageGen.altText,
        mediaId: imageGen.mediaId
    },

    // Мета-данные
    metadata: {
        brand: trigger.контекст.настройки.brand_name,
        publish_date: new Date().toISOString()
    }
  }
};

return items.map(item => {
  const raw = item.json?.output ?? '';

  // Пытаемся найти JSON регуляркой, если он зарыт в тексте
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  let parsed = null;

  if (jsonMatch) {
    try {
      parsed = JSON.parse(jsonMatch[0].replace(/[\u0000-\u001F\u007F-\u009F]/g, ""));
    } catch (e) {
      parsed = null;
    }
  }

  // ✅ ЕСЛИ УДАЛОСЬ ПАРСИТЬ
  if (parsed) {
    return {
      json: {
        technical_prompt: parsed.technical_prompt ?? "Error: prompt missing",
        alt_text: parsed.alt_text ?? "Изображение по теме статьи" // Фоллбэк, если ключа нет
      }
    };
  }

  // ✅ ЕСЛИ ЭТО ПРОСТО ТЕКСТ (не JSON)
  // Мы пытаемся хотя бы обрезать текст для промпта
  return {
    json: {
      technical_prompt: raw.slice(0, 500), 
      alt_text: "Изображение для " + ($('When Executed by Another Workflow').first().json.контекст?.задача['Главный ключ'] || "статьи")
    }
  };
});

