const results = $input.all();
const sourcePlan = $(['Обогатитель данных']).all();

// УСТАНОВКА ФИЛЬТРА:
const currentTypes = ['TEXT', 'RESEARCH', 'QUOTE']; 
const filteredSource = sourcePlan.filter(item => currentTypes.includes(item.json.type));

return results.map((item, index) => {
    const original = filteredSource[index] ? filteredSource[index].json : null;
    let content = (item.json.output || item.json.final_html || "").trim();

    /**
     * САНИТАЙЗЕР (V.3.0):
     */

    // 1. Убираем обертки Markdown Code Blocks (```html ... ``` или просто ``` ... ```)
    // Регулярное выражение ищет открывающие кавычки с опциональным словом html и закрывающие кавычки.
    content = content.replace(/```(?:html|HTML)?([\s\S]*?)```/g, '$1').trim();

    // 2. Убираем возможные артефакты, если слово "html" осталось в начале строки после очистки кавычек
    if (content.toLowerCase().startsWith('html')) {
        content = content.replace(/^html\s+/i, '').trim();
    }

    // 3. Убираем Markdown-заголовки (# Заголовок), если они просочились
    while (content.startsWith('#')) {
        let lines = content.split('\n');
        lines.shift(); // Удаляем первую строку с решетками
        content = lines.join('\n').trim();
    }

    return {
        json: {
            id: original ? original.id : null,
            type: original ? original.type : null,
            h2_title: original ? original.h2_title : null,
            result: content // Чистый HTML без кавычек и лишних тегов
        }
    };
});

/**
 * ОПИСАНИЕ УЗЛА: "Обертка IMG (Финальная версия)"
 * 
 * ЧТО ДЕЛАЕТ:
 * 1. Сопоставляет 3 результата генерации изображений с их исходными ID из плана.
 * 2. Разделяет мета-данные: длинный SEO-текст уходит в невидимый атрибут 'alt', 
 *    а короткий заголовок раздела (h2_title) становится видимой подписью под фото.
 * 3. Формирует адаптивный HTML-код блока с центрированием и ограничением ширины.
 * 
 * ЗАЧЕМ ЭТО НУЖНО:
 * Чтобы фотографии в статье выглядели аккуратно, не дублировали текст подписи 
 * и корректно индексировались поисковиками.
 */

const results = $input.all();
const allSourceItems = $(['Switch']).all();

// Фильтруем только блоки с типом IMG из начала воркфлоу
const imgSourceBlocks = allSourceItems.filter(item => item.json.type === 'IMG');

return results.map((item, index) => {
    const src = imgSourceBlocks[index];
    if (!src) return null; // нет парного IMG-блока — пропускаем, не падаем
    const original = src.json;

    // В качестве подписи (видимой) используем название раздела
    // Если названия нет - ставим нейтральную фразу
    const captionText = original.h2_title || "Иллюстрация к материалу";

    // Собираем HTML-контейнер
    const htmlImage = `
<figure class="wp-block-image aligncenter size-large" style="margin: 24px auto; text-align: center;">
  <img 
    src="${item.json.mediaUrl}" 
    alt="${item.json.altText}" 
    class="wp-image-${item.json.mediaId}" 
    style="width: 100%; max-width: 800px; height: auto; border-radius: 12px; display: block; margin: 0 auto; box-shadow: 0 4px 15px rgba(0,0,0,0.1);"
    loading="lazy"
  />
  <figcaption style="font-size: 14px; color: #777; margin-top: 10px; font-style: italic; line-height: 1.4;">
    ${captionText}
  </figcaption>
</figure>`.trim();

    return {
        json: {
            id: original.id,
            type: original.type,
            h2_title: original.h2_title,
            result: htmlImage // Чистый HTML-кусок для сборки
        }
    };
}).filter(Boolean);

/**
 * ОПИСАНИЕ УЗЛА: "Финальная сортировка"
 * 
 * ЧТО ДЕЛАЕТ:
 * 1. Собирает все части (parts) из агрегатора.
 * 2. Сортирует их по ID (от 2 до 16).
 * 3. Для каждого блока определяет уровень заголовка (H2 или H3).
 * 4. Возвращает МАССИВ готовых кирпичей.
 */

const input = $json.parts;

// 1. Сортируем по ID
input.sort((a, b) => a.id - b.id);

// 2. Добавляем мета-данные верстки к каждому блоку
const bricks = input.map(block => {
  // Определяем тег заголовка
  let headerTag = 'h2';
  if (['TABLE', 'STEPS', 'SOFT_OFFER'].includes(block.type)) {
    headerTag = 'h3';
  }
  if (block.type === 'IMG') {
    headerTag = null; // У картинок заголовка нет
  }

  return {
    id: block.id,
    type: block.type,
    title: block.h2_title,
    header_tag: headerTag,
    content: block.result // Здесь либо текст, либо объект картинки
  };
});

// 3. Возвращаем один итем, содержащий массив всех блоков
return [
  {
    json: {
      blocks: bricks
    }
  }
];

