// Оставляем первый блок для истории, но не для поиска
const plan = $json.final_plan.blocks || [];
const bodyPlan = plan.slice(1);

// Формируем массив задач для поиска
const searchTasks = bodyPlan
  .filter(b => b.perplexity_intent && b.perplexity_intent !== null)
  .map(b => {
    return {
      block_id: b.id,
      type: b.type || null,
      h2: b.h2_title || null,
      query: b.perplexity_intent,
      context: b.context || null,

      external_url: b.external_linking?.url || null,
      external_portal: b.external_linking?.portal || null,
      external_description: b.external_linking?.description || null,

      internal_url: b.internal_linking?.url || null,
      internal_anchor: b.internal_linking?.anchor || null,
      internal_topic: b.internal_linking?.topic || null,

      offer_id: b.offer_id || null,
      offer_url: b.offer_url || null,
    };
  });

// Возвращаем как список элементов для n8n (Split Out)
return searchTasks;

const results = $input.all();
const sourcePlan = $(['Обогатитель данных']).all();

// УСТАНОВКА ФИЛЬТРА:
// Для ТЕКСТ: ['TEXT', 'RESEARCH', 'QUOTE']
// Для ТЕХ: ['TABLE', 'STEPS', 'SOFT_OFFER']
const currentTypes = ['TABLE', 'STEPS', 'VIDEO', 'HARD_OFFER', 'SOFT_OFFER'];
const filteredSource = sourcePlan.filter(item => currentTypes.includes(item.json.type));

function stripTags(value) {
    return String(value || '')
        .replace(/<[^>]+>/g, ' ')
        .replace(/&nbsp;/gi, ' ')
        .replace(/\s+/g, ' ')
        .trim();
}

function escapeHtml(value) {
    return String(value || '')
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#39;');
}

function escapeAttribute(value) {
    return escapeHtml(value);
}

function normalizeHardOffer(html) {
    if (!html || !html.includes('hard-cta-box')) {
        return html;
    }

    let normalized = html;

    // Меняем только фон и базовый цвет текста у самой плашки.
    normalized = normalized.replace(/<div([^>]*class=["'][^"']*hard-cta-box[^"']*["'][^>]*)style=(["'])(.*?)\2([^>]*)>/i, (_match, before, quote, style, after) => {
        const cleanedStyle = String(style)
            .replace(/background\s*:[^;]+;?/gi, '')
            .replace(/color\s*:[^;]+;?/gi, '')
            .replace(/!important/gi, '')
            .replace(/\s{2,}/g, ' ')
            .trim();

        const baseStyle = 'background: #111827; color: #fff;';
        const mergedStyle = cleanedStyle ? `${baseStyle} ${cleanedStyle}` : baseStyle;

        return `<div${before}style=${quote}${mergedStyle}${quote}${after}>`;
    });

    // Меняем только цвет заголовка внутри плашки.
    normalized = normalized.replace(/<h3([^>]*)style=(["'])(.*?)\2([^>]*)>/i, (_match, before, quote, style, after) => {
        const cleanedStyle = String(style)
            .replace(/color\s*:[^;]+;?/gi, '')
            .replace(/!important/gi, '')
            .replace(/\s{2,}/g, ' ')
            .trim();

        const baseStyle = 'color: #fff;';
        const mergedStyle = cleanedStyle ? `${baseStyle} ${cleanedStyle}` : baseStyle;

        return `<h3${before}style=${quote}${mergedStyle}${quote}${after}>`;
    });

    // Меняем только цвет обычных абзацев, не трогая кнопку и ее контейнер.
    normalized = normalized.replace(/<p([^>]*)style=(["'])(.*?)\2([^>]*)>([\s\S]*?)<\/p>/gi, (match, before, quote, style, after, inner) => {
        if (String(inner).includes('<a ')) {
            return match;
        }

        const cleanedStyle = String(style)
            .replace(/color\s*:[^;]+;?/gi, '')
            .replace(/!important/gi, '')
            .replace(/\s{2,}/g, ' ')
            .trim();

        const baseStyle = 'color: #fff;';
        const mergedStyle = cleanedStyle ? `${baseStyle} ${cleanedStyle}` : baseStyle;

        return `<p${before}style=${quote}${mergedStyle}${quote}${after}>${inner}</p>`;
    });

    return normalized;
}

function normalizeSoftOffer(html, original) {
    const rawHtml = String(html || '').trim();
    const firstAnchorMatch = rawHtml.match(/<a[^>]*href=["']([^"']+)["'][^>]*>([\s\S]*?)<\/a>/i);
    const paragraphMatches = [...rawHtml.matchAll(/<p[^>]*>([\s\S]*?)<\/p>/gi)];

    const introFromParagraph = paragraphMatches.find(match => !String(match[1]).includes('<a '));
    const introText = stripTags(introFromParagraph ? introFromParagraph[1] : rawHtml);

    const offerUrl = firstAnchorMatch?.[1] || original?.full_offer?.ссылка || original?.offer_url || '';
    const anchorRawText = stripTags(firstAnchorMatch?.[2] || '');
    const offerName = anchorRawText || original?.full_offer?.название || original?.offer_title || original?.h2_title || 'Перейти';
    const linkLabel = /перейти/i.test(offerName) ? offerName : `${offerName} — Перейти →`;

    const safeIntro = escapeHtml(introText || 'Узнайте подробности по предложению и перейдите по ссылке ниже.');
    const safeUrl = escapeAttribute(offerUrl);
    const safeLinkLabel = escapeHtml(linkLabel);

    return `<div class="ad-box" style="padding: 20px; border-left: 4px solid #7a00ff; background: #f9f9f9; margin: 25px 0; text-align: left;">\n  <p><strong>${safeIntro}</strong></p>\n  <p><a href="${safeUrl}" target="_blank" rel="nofollow noopener" style="color: #7a00ff; text-decoration: underline;">${safeLinkLabel}</a></p>\n</div>`;
}

return results.map((item, index) => {
    const original = filteredSource[index] ? filteredSource[index].json : null;
    let content = (item.json.output || item.json.final_html || "").trim();

    /**
     * САНИТАЙЗЕР (V.2.0):
     * Пока первая строка текста начинается с решетки (#),
     * мы отрезаем эту строку целиком. Это убирает любые H1-H6.
     */
    while (content.startsWith('#')) {
        let lines = content.split('\n');
        lines.shift();
        content = lines.join('\n').trim();
    }

    if (original && original.type === 'HARD_OFFER') {
        content = normalizeHardOffer(content);
    }

    if (original && original.type === 'SOFT_OFFER') {
        content = normalizeSoftOffer(content, original);
    }

    return {
        json: {
            id: original.id,
            type: original.type,
            h2_title: original.h2_title,
            result: content
        }
    };
});

/**
 * УЗЕЛ: Обогатитель данных V.10.0
 * ЧТО ДЕЛАЕТ:
 * 1. Соединяет план Архитектора с результатами поиска Perplexity.
 * 2. Разворачивает offer_id в полные данные (ссылка, название, текст).
 * 3. Сохраняет старый формат выхода для следующих узлов.
 * 4. При наличии research-результата обновляет research_data и linking-поля блока.
 */

const researchItems = $items("Агент Исследователь");
const researchMap = {};

// Собираем карту исследований по block_id
researchItems.forEach(item => {
	try {
		const raw = (item.json.output || '').replace(/```json\s*|```/g, '').trim();
		if (!raw) return;

		const parsed = JSON.parse(raw);

		// Новый формат
		if (parsed && parsed.block_id !== undefined && parsed.block_id !== null) {
			researchMap[String(parsed.block_id)] = {
				research_summary: parsed.research_summary || "Данные из досье.",
				external_linking: parsed.external_linking || null,
				internal_linking: parsed.internal_linking || null,
			};
			return;
		}

		// Legacy fallback: {"ID": "text"}
		if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
			const keys = Object.keys(parsed);
			if (keys.length === 1) {
				const id = keys[0];
				researchMap[String(id)] = {
					research_summary: parsed[id] || "Данные из досье.",
					external_linking: null,
					internal_linking: null,
				};
			}
		}
	} catch (e) {
		console.log("Research output is not valid JSON:", e.message);
	}
});

// Источник плана и контекста оставляем как раньше
const triggerItem = $('When Executed by Another Workflow').first().json;
const planBlocks = triggerItem.final_plan.blocks || [];
const offersDb = triggerItem.контекст?.база_офферов || [];

// глава (ближайший заголовок раздела) для каждого блока — вперёд, потом назад
function __chapterFor(idx){for(let i=idx+1;i<planBlocks.length;i++){const h=planBlocks[i].h2_title;if(h&&String(h).trim())return String(h).trim();}for(let i=idx-1;i>=0;i--){const h=planBlocks[i].h2_title;if(h&&String(h).trim())return String(h).trim();}return '';}
const __chapterMap={};
planBlocks.forEach((b,i)=>{const h=b.h2_title;__chapterMap[String(b.id)]=(h&&String(h).trim())?String(h).trim():__chapterFor(i);});

// Собираем enriched items
return planBlocks
	.filter(b => b.id !== 1)
	.map(block => {
		const research = researchMap[String(block.id)] || null;

		const blockFacts = research?.research_summary || "Данные из досье.";

		// Разворачиваем оффер по ID, с учетом number/string
		let fullOfferData = null;
		if (block.offer_id !== null && block.offer_id !== undefined && block.offer_id !== '') {
			fullOfferData =
				offersDb.find(o => String(o.id) === String(block.offer_id)) || null;
		}

		// Если research вернул более точный external_linking/internal_linking, используем его
		const external_linking =
			research?.external_linking !== undefined && research?.external_linking !== null
				? research.external_linking
				: (block.external_linking || null);

		const internal_linking =
			research?.internal_linking !== undefined && research?.internal_linking !== null
				? research.internal_linking
				: (block.internal_linking || null);

		// Если оффер найден, offer_url можно канонизировать через full_offer, но поле формата не ломаем
		const offer_url =
			fullOfferData?.ссылка ||
			block.offer_url ||
			null;

		return {
			json: {
				...block,
				external_linking,
				internal_linking,
				offer_url,
				research_data: blockFacts,
				full_offer: fullOfferData,
				video_data: block.video_data || null,
				languageCode: triggerItem.languageCode,
				chapter_title: __chapterMap[String(block.id)] || '',
			}
		};
	});

/**
 * ОПИСАНИЕ УЗЛА: "Очистка референсов (Массовая)"
 * 
 * ЧТО ДЕЛАЕТ:
 * 1. Использует метод $input.all(), чтобы получить весь список входящих задач.
 * 2. Проходит по каждому итему через .map().
 * 3. Проверяет поле "ref_url". Если ссылка битая или пустая — заменяет её на null.
 * 4. Сохраняет поля prompt и alt_text без изменений.
 */

return $input.all().map(item => {
  let cleanRef = item.json.ref_url;

  if (!cleanRef || 
      typeof cleanRef !== 'string' || 
      !cleanRef.trim().startsWith('http')) 
  {
      cleanRef = null; 
  }

  return {
    json: {
      prompt: item.json.prompt,
      ref_url: cleanRef,
      alt_text: item.json.alt_text,
      wp_url: item.json.wp_url
    }
  };
});

// Извлекаем taskId из ответа KIE AI
// Логируем весь ответ для диагностики
const response = $json;
const taskId = response.data?.taskId || response.taskId || response.data?.task_id;

if (!taskId) {
  throw new Error('❌ Не получен taskId от KIE AI. Ответ: ' + JSON.stringify(response).substring(0, 500));
}

// Сохраняем prompt и ref_url для возможного ретрая
const prevData = $('Очистка референсов').first().json;
return [{ json: { taskId, prompt: prevData.prompt, ref_url: prevData.ref_url, alt_text: prevData.alt_text } }];

/**
 * Парсер ответа KIE AI.
 * Приводим формат к единому виду для Switch:
 * - status: success | queued | failed
 * - resultUrl (если success)
 * - taskId (для повторных проверок)
 * - prompt, ref_url (для ретрая генерации)
 */
const data = $json.data || $json;
const state = (data.state || '').toLowerCase();

let status = 'queued';
let resultUrl = null;

if (state === 'success') {
  status = 'success';
  try {
    const resultJson = JSON.parse(data.resultJson || '{}');
    resultUrl = (resultJson.resultUrls || [])[0] || null;
  } catch (e) {
    resultUrl = null;
  }
} else if (state === 'fail' || state === 'failed') {
  status = 'failed';
} else {
  status = 'queued';
}

// Берём prompt/ref_url из ноды Очистка референсов для ретрая
let prompt, ref_url;
try {
  const prev = $('Очистка референсов').first().json;
  prompt = prev.prompt;
  ref_url = prev.ref_url;
} catch(e) {
  prompt = null;
  ref_url = null;
}

return [{
  json: {
    status,
    resultUrl,
    taskId: data.taskId || $json.taskId,
    prompt,
    ref_url
  }
}];

/**
 * Подготовка данных медиа для возврата в вызывающий workflow.
 * Формат совместим с нодой "Сборка HOOK" в ВФ 2.
 */
const altText = $('Loop Over Items').item.json.alt_text;
return [{
  json: {
    mediaUrl: $json.source_url || $json.guid?.rendered || '',
    altText: altText,
    mediaId: $json.id
  }
}];

const MAX_ATTEMPTS = 20;

const state = $getWorkflowStaticData('node');

if (!state.statusFailCount) {
  state.statusFailCount = 0;
}

state.statusFailCount += 1;

if (state.statusFailCount >= MAX_ATTEMPTS) {
  state.statusFailCount = 0;
  throw new Error(
    `❌ Статус не изменился после ${MAX_ATTEMPTS} попыток. KIE AI не отвечает или завис. Workflow остановлен.`
  );
}

// Пропускаем ВСЕ данные насквозь без изменений
return $input.all().map(item => ({ json: item.json }));

const MAX_ATTEMPTS = 5;

const state = $getWorkflowStaticData('node');

if (!state.failCount) {
  state.failCount = 0;
}

state.failCount += 1;

if (state.failCount >= MAX_ATTEMPTS) {
  state.failCount = 0;
  throw new Error(
    `❌ Генерация провалилась ${MAX_ATTEMPTS} раза. Проверь баланс в KIE AI.`
  );
}

// Пропускаем ВСЕ данные насквозь без изменений
return $input.all().map(item => ({ json: item.json }));

const existing=new Set($input.all().map(r=>(r.json&&r.json.ID!=null)?String(r.json.ID):'').filter(Boolean));
const resp=await this.helpers.httpRequest({method:'GET',url:'https://__BLOG_DOMAIN__/wp-json/wp/v2/posts',
  qs:{per_page:100,status:'publish',orderby:'date',order:'desc',_fields:'id,date,title,content,link,featured_media'},json:true});
function htmlToPlain(html){
  if(!html) return '';
  let s=html;
  s=s.replace(/<script[\s\S]*?<\/script>/gi,'');
  s=s.replace(/<style[\s\S]*?<\/style>/gi,'');
  function stripDiv(str, cls){
    for(let g=0; g<100; g++){
      let pos=0, ds=-1;
      while(true){
        const d=str.indexOf('<div', pos);
        if(d<0) break;
        const gt=str.indexOf('>', d);
        if(gt<0) break;
        const tag=str.slice(d, gt+1);
        if(tag.indexOf('class="')!==-1 && tag.indexOf(cls)!==-1){ ds=d; break; }
        pos=gt+1;
      }
      if(ds<0) break;
      let depth=0, i=ds, end=-1;
      while(i<str.length){
        if(str.startsWith('<div', i)){ depth++; const x=str.indexOf('>', i); if(x<0){break;} i=x+1; continue; }
        if(str.startsWith('</div', i)){ depth--; const x=str.indexOf('>', i); if(x<0){break;} i=x+1; if(depth===0){ end=i; break; } continue; }
        i++;
      }
      if(end<0) break;
      str=str.slice(0,ds)+str.slice(end);
    }
    return str;
  }
  ['stats-box','toc-box','author-card','ad-box','hard-cta-box'].forEach(function(c){ s=stripDiv(s,c); });
  s=s.replace(/<figure[\s\S]*?<\/figure>/gi,'');
  s=s.replace(/<img[^>]*>/gi,'');
  s=s.replace(/<\/(td|th)>/gi,' \t ');
  s=s.replace(/<li[^>]*>([\s\S]*?)<\/li>/gi,function(m,t){return t.trim()+'\n';});
  s=s.replace(/<\/(p|div|h[1-6]|ul|ol|table|tr|blockquote|figcaption)>/gi,'\n\n');
  s=s.replace(/<br\s*\/?>/gi,'\n');
  s=s.replace(/<[^>]+>/g,'');
  s=s.replace(/&nbsp;/g,' ').replace(/&amp;/g,'&').replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&quot;/g,'"').replace(/&#0?39;/g,"'").replace(/&laquo;/g,'«').replace(/&raquo;/g,'»').replace(/&mdash;/g,'—').replace(/&ndash;/g,'–').replace(/&#\d+;/g,'');
  s=s.replace(/ +/g,' ').replace(/ *\n */g,'\n').replace(/\n{3,}/g,'\n\n');
  return s.trim();
}

const out=[];
for(const p of resp){
  if(existing.has(String(p.id))) continue;
  const html=(p.content&&p.content.rendered)||p.content||'';
  const title=(p.title&&p.title.rendered)||p.title||'';
  let feat='';if(p.featured_media){try{const __m=await this.helpers.httpRequest({method:'GET',url:'https://__BLOG_DOMAIN__/wp-json/wp/v2/media/'+p.featured_media,qs:{_fields:'source_url'},json:true});feat=(__m&&__m.source_url)||'';}catch(e){}}const bodyImgs=[...html.matchAll(/<img[^>]*?src="([^"]+)"/gi)].map(m=>m[1]);const imgs=[...new Set([feat,...bodyImgs].filter(u=>u&&u.includes('/wp-content/uploads/')))];
  out.push({json:{"ID":String(p.id),"Дата/время":(p.date||'').replace('T',' ').slice(0,16),"Тема":title,"Текст":htmlToPlain(html),"Картинки":imgs.join('\n\n')}});
}
return out;
